+/**
+ * Update alert configuration.
+ */
+export function updateAlertConfig(
+  config: Partial<ConflictAlertConfig>,
+): ConflictAlertConfig {
+  alertConfig = { ...alertConfig, ...config };
+  return alertConfig;
+}
